export const CUSTOM_PROXY_GROUP_ICON_NAME = '自定义-代理'
export const CUSTOM_DIRECT_PROXY_GROUP_ICON_NAME = '自定义-直连'
export const CUSTOM_PROXY_GROUP_LEGACY_ICON_NAMES = ['自定义', '路飞']
export const CUSTOM_PROXY_GROUP_ICON_UUID = '22d36ad7-f2cb-4ff9-b4a4-e7f0d2dc0a5b'
export const CUSTOM_DIRECT_PROXY_GROUP_ICON_UUID = '8f949d69-cd69-4773-b62f-61aeb5150cf2'
export const CUSTOM_PROXY_GROUP_ICON =
  'data:image/svg+xml;base64,'
export const CUSTOM_DIRECT_PROXY_GROUP_ICON =
  'data:image/svg+xml;base64,'
export const ICON_REFLECT_LIST_KEY = 'config/icon-reflect-list'

type IconReflectItem = Record<string, unknown> & {
  name: string
  icon?: string
  uuid?: string
}

type CustomIconDefinition = {
  names: string[]
  icon: string
  uuid: string
}

const CUSTOM_ICON_DEFINITIONS: CustomIconDefinition[] = [
  {
    names: [CUSTOM_PROXY_GROUP_ICON_NAME, ...CUSTOM_PROXY_GROUP_LEGACY_ICON_NAMES],
    icon: CUSTOM_PROXY_GROUP_ICON,
    uuid: CUSTOM_PROXY_GROUP_ICON_UUID,
  },
  {
    names: [CUSTOM_DIRECT_PROXY_GROUP_ICON_NAME],
    icon: CUSTOM_DIRECT_PROXY_GROUP_ICON,
    uuid: CUSTOM_DIRECT_PROXY_GROUP_ICON_UUID,
  },
]

const parseIconReflectList = (value: unknown) => {
  if (Array.isArray(value)) return value

  if (typeof value !== 'string' || !value.trim()) return []

  try {
    const parsedIconReflectList = JSON.parse(value)

    return Array.isArray(parsedIconReflectList) ? parsedIconReflectList : []
  } catch {
    return []
  }
}

const isIconReflectItem = (item: unknown): item is IconReflectItem => {
  return Boolean(
    item &&
    typeof item === 'object' &&
    'name' in item &&
    typeof item.name === 'string' &&
    item.name.trim(),
  )
}

const getCustomIconDefinition = (item: IconReflectItem) => {
  const name = item.name.trim()

  return CUSTOM_ICON_DEFINITIONS.find((definition) => {
    return (
      definition.names.includes(name) ||
      item.uuid === definition.uuid ||
      item.icon === definition.icon
    )
  })
}

export const ensureCustomProxyGroupIconInSettings = (settings: Record<string, unknown>) => {
  const iconReflectList = parseIconReflectList(settings[ICON_REFLECT_LIST_KEY])
  const customIconNames = new Map<CustomIconDefinition, Set<string>>()

  CUSTOM_ICON_DEFINITIONS.forEach((definition) => {
    customIconNames.set(definition, new Set(definition.names))
  })

  iconReflectList.filter(isIconReflectItem).forEach((item) => {
    const definition = getCustomIconDefinition(item)

    if (definition) {
      customIconNames.get(definition)?.add(item.name.trim())
    }
  })

  const seenNames = new Set<string>()
  const nextIconReflectList: IconReflectItem[] = []

  iconReflectList.filter(isIconReflectItem).forEach((item) => {
    const name = item.name.trim()

    if (seenNames.has(name)) return

    const definition = getCustomIconDefinition(item)

    seenNames.add(name)
    nextIconReflectList.push(
      definition
        ? {
            ...item,
            name,
            icon: definition.icon,
            uuid: definition.uuid,
          }
        : {
            ...item,
            name,
          },
    )
  })

  customIconNames.forEach((names, definition) => {
    names.forEach((name) => {
      if (seenNames.has(name)) return

      nextIconReflectList.push({
        name,
        icon: definition.icon,
        uuid: definition.uuid,
      })
      seenNames.add(name)
    })
  })

  settings[ICON_REFLECT_LIST_KEY] = JSON.stringify(nextIconReflectList)

  return settings
}
